sys_script.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	// 2.5.13:  08.10.20  | KT | SEQ | STRY0076789: SEQ - Task Form - WAIT FOR SUBTASKS TO FINISH Flag Location and Information message

	g_scratchpad.numApprovalSubTasks = 0;

	var countSubtasks = new GlideAggregate('x_153465_discovert_route_task_instance');
	countSubtasks.addQuery('parent', current.sys_id);
	countSubtasks.addQuery('tasker_type', "IN", '614d2f29dbb4d3003a8d6be3ca961920,2206206edb19e300c18c59b2ca961922');
	countSubtasks.addQuery('state', "NOT IN", "3,4,7");
	countSubtasks.addAggregate('COUNT');
	countSubtasks.query();


	if(countSubtasks.next()){
		g_scratchpad.numApprovalSubTasks = countSubtasks.getAggregate('COUNT');
	}

	// STRY0077855 - any subtasks later than parent?
	g_scratchpad.subtaskSuspenseDateOlderThanParent = false;
	var countDateSubtasks = new GlideRecord('x_153465_discovert_route_task_instance');
	countDateSubtasks.addQuery('parent', current.sys_id);
	countDateSubtasks.addQuery('suspense_date','>', current.suspense_date); 
	countDateSubtasks.addNotNullQuery('suspense_date');
	countDateSubtasks.addQuery('state', "NOT IN", "3,4,7");
	countDateSubtasks.query();
	if(countDateSubtasks.next()){
		g_scratchpad.subtaskSuspenseDateOlderThanParent = true;
	}
})(current, previous);
